package com.wjx871.population.cancellation;import com.wjx871.population.application.*;import com.wjx871.population.common.BusinessException;import lombok.RequiredArgsConstructor;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Component;
@Component @RequiredArgsConstructor public class CancellationSubmissionValidator implements ApplicationSubmissionValidator {private final CancellationMapper mapper;private final CancellationMaterialRequirementService materials;public boolean supports(BusinessType t){return t==BusinessType.PERSON_CANCELLATION||t==BusinessType.HOUSEHOLD_CANCELLATION;}public void validate(BusinessApplication a){CancellationRecord r=mapper.findByApplication(a.getApplicationId()).orElse(null);if(r==null)return;if(r.getCancelObjectType()==CancelObjectType.PERSON){CancellationTarget t=mapper.findPersonTarget(r.getPersonId()).orElseThrow(()->bad("人员不存在"));if(isCancelled(t))bad("人员已经注销");validateHead(r,t);}else validateHousehold(mapper.findHouseholdTarget(r.getHouseholdId()).orElseThrow(()->bad("家庭户不存在")),r.getHouseholdId());materials.validate(r);}private void validateHead(CancellationRecord r,CancellationTarget t){if(t.getHouseholdId()!=null&&r.getPersonId().equals(t.getHeadPersonId())&&t.getActiveMemberCount()>1&&(r.getNewHeadPersonId()==null||r.getNewHeadPersonId().equals(r.getPersonId())||!mapper.activeMembers(t.getHouseholdId()).contains(r.getNewHeadPersonId())))bad("户主注销且仍有其他成员时必须指定有效新户主");}private void validateHousehold(CancellationTarget t,Long id){if(!"PENDING_CANCELLATION".equals(t.getHouseholdStatus())||t.getActiveMemberCount()>0||t.getResidenceCount()>0||mapper.countPendingMigrationIn(id)>0)bad("家庭户不满足销户条件");}private boolean isCancelled(CancellationTarget t){return "CANCELLED".equals(t.getCurrentStatusCode())||"DECEASED".equals(t.getCurrentStatusCode());}private BusinessException bad(String m){return new BusinessException(HttpStatus.CONFLICT,m);}}
